const html = $json.data ?? '';
const baseUrl = 'https://hochschulsport.rwth-aachen.de';

const hrefRegex = /href=["']([^"']+)["']/gi;
const hrefs = [...html.matchAll(hrefRegex)].map(m => m[1].trim());

const relevant = [...new Set(
  hrefs.filter(href =>
    href.startsWith('/cms/hsz/sport/Sportangebot/') ||
    href.startsWith('/cms/hsz/events/')
  )
)];

return relevant.map(href => ({
  json: {
    type: href.startsWith('/cms/hsz/events/') ? 'event' : 'sport',
    path: href,
    url: `${baseUrl}${href}`,
    title: decodeURIComponent(href.split('/').filter(Boolean).pop() || ''),
  }
}));

const items = $input.all();
const results = [];

for (const item of items) {
  const html = item.json.data ?? '';

  const bookingLinks = [...html.matchAll(/href="(https:\/\/buchung\.hsz\.rwth-aachen\.de\/angebote\/[^"]+)"/gi)]
    .map(m => m[1].trim());

  const unique = [...new Set(bookingLinks)];

  for (const url of unique) {
    results.push({
      json: {
        sourceTitle: $('Loop Over Items1').first().json.title ?? null,
        sourceType: $('Loop Over Items1').first().json.type ?? null,
        sourceUrl: $('Loop Over Items1').first().json.url ?? null,
        sourcePath: $('Loop Over Items1').first().json.path ?? null,
        rowNumber: $('Loop Over Items1').first().json.row_number ?? null,
        bookingUrl: url,
        semester: url.includes('/Wintersemester/') ? 'Wintersemester'
          : url.includes('/Sommersemester/') ? 'Sommersemester'
          : null,
      }
    });
  }
}

// Fisher-Yates Shuffle
for (let i = results.length - 1; i > 0; i--) {
  const j = Math.floor(Math.random() * (i + 1));
  [results[i], results[j]] = [results[j], results[i]];
}

return results.length ? results : [{
  json: {
    message: 'Keine Buchungslinks gefunden',
    inputItemCount: items.length,
  }
}];

// Loop over input items and add a new field called 'myNewField' to the JSON of each one
for (const item of $input.all()) {
  item.json.myNewField = 1;
}

return $input.all();

