      bookingUrl: $json.bookingUrl,
      cleanBookingUrl: String($json.bookingUrl || $json.url || '')
        .trim()
        .replace(/[\r\n\t]/g, '')
        .replace(/\s+/g, ''),
      title: $json.title ?? null,
      sourceTitle: $input.first().json.sourceTitle ?? null,
    }
  }
];

