for (const item of $input.all()) {
  item.json.myNewField = 1;
}

return $input.all();

const courses = $json.courses || [];
const sport = $json.sport || null;

function cleanText(value) {
  return (value || '')
    .replace(/\[\/cgi\/webpage\.cgi\?[^\]]+\]/g, '')
    .replace(/\n+/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();
}

function random10DigitNumber() {
  return '--' + Math.floor(1000000000 + Math.random() * 9000000000).toString();
}

function isDay(value) {
  return /^(Mo|Di|Mi|Do|Fr|Sa|So)$/i.test(cleanText(value));
}

function isDateRange(value) {
  const v = cleanText(value);
  return /^\d{2}\.\d{2}\.\d{2,4}\s*-\s*\d{2}\.\d{2}\.\d{2,4}/.test(v)
    || /^\d{2}\.\d{2}\.\s*-\s*\d{2}\.\d{2}\./.test(v)
    || /^\d{2}\.\d{2}\.\d{4}\s*-\s*\d{2}\.\d{2}\.\d{4}/.test(v);
}

function isPrice(value) {
  return /€/.test(cleanText(value));
}

function isBookingStatus(value) {
  const v = cleanText(value).toLowerCase();
  return /buchung|ausgebucht|warteliste|belegt|keine buchung/.test(v);
}

function isCourseNumber(value) {
  const v = cleanText(value);
  return /^\d+$/.test(v) || /^--\d{10}$/.test(v);
}

const cleaned = courses.map(cleanText).filter(Boolean);
const out = [];

let i = 0;

while (i < cleaned.length) {
  let courseNumber = cleaned[i] || '';
  if (!isCourseNumber(courseNumber)) {
    i++;
    continue;
  }

  courseNumber = courseNumber || random10DigitNumber();
  i++;

  const details = cleaned[i] || '';
  i++;

  const scheduleBlocks = [];

  while (
    i + 2 < cleaned.length &&
    isDay(cleaned[i])
  ) {
    scheduleBlocks.push({
      day: cleaned[i] || '',
      time: cleaned[i + 1] || '',
      location: cleaned[i + 2] || '',
    });
    i += 3;
  }

  let duration = '';
  let instructor = '';
  let price = '';
  let bookingStatus = '';

  if (i < cleaned.length && isDateRange(cleaned[i])) {
    duration = cleaned[i];
    i++;
  }

  if (i < cleaned.length && !isPrice(cleaned[i]) && !isBookingStatus(cleaned[i]) && !isCourseNumber(cleaned[i])) {
    instructor = cleaned[i];
    i++;
  }

  if (i < cleaned.length && isPrice(cleaned[i])) {
    price = cleaned[i];
    i++;
  }

  if (i < cleaned.length && isBookingStatus(cleaned[i])) {
    bookingStatus = cleaned[i];
    i++;
  }

  out.push({
    json: {
      sport,
      courseNumber,
      details,
      day: scheduleBlocks.map(x => x.day).join(' | '),
      time: scheduleBlocks.map(x => x.time).join(' | '),
      location: scheduleBlocks.map(x => x.location).join(' | '),
      duration,
      instructor,
      price,
      bookingStatus,
      scheduleCount: scheduleBlocks.length,
    }
  });
}

return out;

return items.map(item => {
  const details = item.json.details || '';

  return {
    json: {
      ...item.json,
      Einzeltermin: details.includes('Ein Termin') ? 'ja' : 'nein'
    }
  };
});

