const courses = $json.courses || [];
const bookingLinks = $json.bookingLink || [];
const sport = $json.sport || null;

function cleanText(value) {
  return (value || '')
    .replace(/\[\/cgi\/webpage\.cgi\?[^\]]+\]/g, '')
    .replace(/\n+/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();
}

function random10DigitNumber() {
  return '--' + Math.floor(1000000000 + Math.random() * 9000000000).toString();
}

function isDay(value) {
  return /^(Mo|Di|Mi|Do|Fr|Sa|So)$/i.test(cleanText(value));
}

function isTimeRange(value) {
  return /^(\d{1,2}):(\d{2})\s*-\s*(\d{1,2}):(\d{2})$/.test(cleanText(value));
}

function isDateRange(value) {
  const v = cleanText(value);
  return /^\d{2}\.\d{2}\.\d{4}$/.test(v)
    || /^\d{2}\.\d{2}\.$/.test(v)
    || /^\d{2}\.\d{2}\.\d{2,4}\s*-\s*\d{2}\.\d{2}\.\d{2,4}$/.test(v)
    || /^\d{2}\.\d{2}\.\s*-\s*\d{2}\.\d{2}\.$/.test(v);
}

function isPrice(value) {
  return /€/.test(cleanText(value));
}

function isCourseNumber(value) {
  const v = cleanText(value);
  return /^\d+$/.test(v) || /^--\d{10}$/.test(v);
}

function extractBookingStatus(html) {
  const raw = html || '';

  const valueMatch = raw.match(/value="([^"]+)"/i);
  if (valueMatch) return cleanText(valueMatch[1]);

  const textMatch = raw.match(/>([^<]+)</);
  if (textMatch) return cleanText(textMatch[1]);

  return '';
}

function pad(num) {
  return String(num).padStart(2, '0');
}

function toIsoLocal(year, month, day, hour = 0, minute = 0) {
  return `${year}-${pad(month)}-${pad(day)}T${pad(hour)}:${pad(minute)}:00`;
}

function parseTimeRange(timeText) {
  const v = cleanText(timeText);
  const match = v.match(/^(\d{1,2}):(\d{2})\s*-\s*(\d{1,2}):(\d{2})$/);

  if (!match) {
    return {
      startHour: null,
      startMinute: null,
      endHour: null,
      endMinute: null,
    };
  }

  return {
    startHour: Number(match[1]),
    startMinute: Number(match[2]),
    endHour: Number(match[3]),
    endMinute: Number(match[4]),
  };
}

function parseDateRange(durationText) {
  const v = cleanText(durationText).replace(/\s+/g, '');
  const currentYear = new Date().getFullYear();

  let match = v.match(/^(\d{2})\.(\d{2})\.(\d{4})-(\d{2})\.(\d{2})\.(\d{4})$/);
  if (match) {
    return {
      type: 'range',
      startDay: Number(match[1]),
      startMonth: Number(match[2]),
      startYear: Number(match[3]),
      endDay: Number(match[4]),
      endMonth: Number(match[5]),
      endYear: Number(match[6]),
    };
  }

  match = v.match(/^(\d{2})\.(\d{2})\.-(\d{2})\.(\d{2})\.$/);
  if (match) {
    const startDay = Number(match[1]);
    const startMonth = Number(match[2]);
    const endDay = Number(match[3]);
    const endMonth = Number(match[4]);
    const startYear = currentYear;
    const endYear = endMonth < startMonth ? startYear + 1 : startYear;

    return {
      type: 'range',
      startDay,
      startMonth,
      startYear,
      endDay,
      endMonth,
      endYear,
    };
  }

  match = v.match(/^(\d{2})\.(\d{2})\.(\d{4})$/);
  if (match) {
    const day = Number(match[1]);
    const month = Number(match[2]);
    const year = Number(match[3]);

    return {
      type: 'single',
      startDay: day,
      startMonth: month,
      startYear: year,
      endDay: day,
      endMonth: month,
      endYear: year,
    };
  }

  match = v.match(/^(\d{2})\.(\d{2})\.$/);
  if (match) {
    const day = Number(match[1]);
    const month = Number(match[2]);

    return {
      type: 'single',
      startDay: day,
      startMonth: month,
      startYear: currentYear,
      endDay: day,
      endMonth: month,
      endYear: currentYear,
    };
  }

  return null;
}

function buildScheduleTimes(timeText, durationText) {
  const time = parseTimeRange(timeText);
  const range = parseDateRange(durationText);

  if (
    !range ||
    time.startHour === null ||
    time.startMinute === null ||
    time.endHour === null ||
    time.endMinute === null
  ) {
    return {
      start: '',
      end: '',
      recurringEnd: '',
      isRecurring: false,
    };
  }

  return {
    start: toIsoLocal(
      range.startYear,
      range.startMonth,
      range.startDay,
      time.startHour,
      time.startMinute
    ),
    end: toIsoLocal(
      range.startYear,
      range.startMonth,
      range.startDay,
      time.endHour,
      time.endMinute
    ),
    recurringEnd: toIsoLocal(
      range.endYear,
      range.endMonth,
      range.endDay,
      23,
      59
    ),
    isRecurring: range.type === 'range',
  };
}

function looksLikeLocation(value) {
  const v = cleanText(value);
  if (!v) return false;
  if (isDay(v) || isTimeRange(v) || isDateRange(v) || isPrice(v) || isCourseNumber(v)) return false;
  return true;
}

const cleaned = courses.map(cleanText).filter(Boolean);
const out = [];

let i = 0;
let bookingIndex = 0;

while (i < cleaned.length) {
  let courseNumber = cleaned[i] || '';
  if (!isCourseNumber(courseNumber)) {
    i++;
    continue;
  }

  courseNumber = courseNumber || random10DigitNumber();
  i++;

  const details = cleaned[i] || '';
  i++;

  const scheduleBlocks = [];

  while (i < cleaned.length && isDay(cleaned[i])) {
    const day = cleaned[i] || '';
    const time = cleaned[i + 1] || '';
    let location = '';

    if (!isTimeRange(time)) break;

    i += 2;

    const nextValue = cleaned[i] || '';
    if (looksLikeLocation(nextValue)) {
      location = nextValue;
      i++;
    }

    scheduleBlocks.push({
      day,
      time,
      location,
    });
  }

  let duration = '';
  let instructor = '';
  let price = '';

  if (i < cleaned.length && isDateRange(cleaned[i])) {
    duration = cleaned[i];
    i++;
  }

  if (i < cleaned.length && !isPrice(cleaned[i]) && !isCourseNumber(cleaned[i])) {
    instructor = cleaned[i];
    i++;
  }

  if (i < cleaned.length && isPrice(cleaned[i])) {
    price = cleaned[i];
    i++;
  }

  const bookingStatus = extractBookingStatus(bookingLinks[bookingIndex]);
  bookingIndex++;

  for (const block of scheduleBlocks) {
    const scheduleTimes = buildScheduleTimes(block.time, duration);

    out.push({
      json: {
        sport,
        courseNumber,
        details,
        day: block.day,
        time: block.time,
        location: block.location || '',
        duration,
        instructor,
        price,
        bookingStatus,
        start: scheduleTimes.start,
        end: scheduleTimes.end,
        recurringEnd: scheduleTimes.recurringEnd,
        isRecurring: scheduleTimes.isRecurring,
      }
    });
  }
}

return out;

return items.map(item => {
  const details = item.json.details || '';

  return {
    json: {
      ...item.json,
      Einzeltermin: details.includes('Ein Termin') ? 'ja' : 'nein'
    }
  };
});
